const j = $input.first().json;
const action = $('Build Prompt').item.json.action;
let result = '';
if (Array.isArray(j.content)) {
  result = j.content.map(c => c.text || '').join('');
} else {
  result = String(j.content || j.text || '');
}
return [{ json: { result: result.trim(), action } }];

